import{_ as e,o as a,c as n,an as i}from"./chunks/framework.D5fFzH9V.js";const h=JSON.parse('{"title":"YubiKey setup","description":"Setup guide for using a YubiKey for PIV/SSH (Windows) and basic GPG/SSH agent configuration.","frontmatter":{"title":"YubiKey setup","description":"Setup guide for using a YubiKey for PIV/SSH (Windows) and basic GPG/SSH agent configuration."},"headers":[],"relativePath":"organization/human-resources/yubikey-setup.md","filePath":"organization/human-resources/yubikey-setup.md"}'),t={name:"organization/human-resources/yubikey-setup.md"};function o(p,s,l,r,c,d){return a(),n("div",null,[...s[0]||(s[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /organization/human-resources/yubikey-setup.md for this page in Markdown format</div><h1 id="yubikey-setup" tabindex="-1">YubiKey setup <a class="header-anchor" href="#yubikey-setup" aria-label="Permalink to &quot;YubiKey setup&quot;">​</a></h1><h2 id="piv" tabindex="-1">PIV <a class="header-anchor" href="#piv" aria-label="Permalink to &quot;PIV&quot;">​</a></h2><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><p>Prerequisites:</p><ul><li>Install <a href="https://github.com/OpenSC/OpenSC/releases/latest" target="_blank" rel="noreferrer">OpenSC Library for PKCS11</a> (<a href="https://github.com/OpenSC/OpenSC/wiki" target="_blank" rel="noreferrer">Documentation</a>)</li><li>Install <a href="https://github.com/Yubico/yubikey-manager/releases/latest" target="_blank" rel="noreferrer">Yubikey Manager CLI</a></li><li>Yubico Authenticator</li><li>Have your PIN and Management Key ready (store in Vaultwarden)</li><li>Make sure, OpenSC ignores Windows Hello (see Troubleshooting below)</li><li>Make sure, you use supported algorithms (see Troubleshooting below)</li></ul><hr><ol><li>Generate a keypair (select one of the working algos: prefer <code>eccp384</code> over <code>rsa3072</code> over <code>rsa2048</code>):</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ykman piv keys generate --touch-policy never --pin-policy once -a eccp384 9a pubkey.pem</span></span></code></pre></div><ol start="2"><li>Create a self signed cert based on this key:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ykman piv certificates generate 9a pubkey.pem --subject &quot;CN=SSH Key&quot; --valid-days 36500</span></span></code></pre></div><ol start="3"><li>Retrieve your public key and add to <code>~/.ssh/authorized_keys</code> on the remote host:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh-keygen -D &quot;C:\\Program Files\\OpenSC Project\\OpenSC\\pkcs11\\opensc-pkcs11.dll&quot;</span></span></code></pre></div><ol start="4"><li>Connect with ssh:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh -I &quot;C:\\Program Files\\OpenSC Project\\OpenSC\\pkcs11\\opensc-pkcs11.dll&quot; user@IP</span></span></code></pre></div><ol start="5"><li>(Recommended) Add to your <code>~\\.ssh\\config</code> (create file if it doesn&#39;t exist):</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PKCS11Provider &quot;C:\\Program Files\\Yubico\\Yubico PIV Tool\\bin\\libykcs11.dll&quot;</span></span></code></pre></div><h4 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h4><hr><h5 id="windows-hello" tabindex="-1">Windows Hello <a class="header-anchor" href="#windows-hello" aria-label="Permalink to &quot;Windows Hello&quot;">​</a></h5><p>It is possible that OpenSC recognizes &quot;Windows Hello&quot; as its own device, thus you extract its RSA key. To prevent this, modify <code>C:\\Program Files\\OpenSC Project\\OpenSC\\opensc.conf</code> to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app default {</span></span>
<span class="line"><span>	# debug = 3;</span></span>
<span class="line"><span>	# debug_file = opensc-debug.txt;</span></span>
<span class="line"><span>	ignored_readers = &quot;Windows Hello&quot; ; # Ignore all readers containing &quot;Windows Hello&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>To list all devices, run <code>&amp; &quot;C:\\Program Files\\OpenSC Project\\OpenSC\\tools\\opensc-tool.exe&quot; --list-readers</code> (PowerShell).</p><h5 id="error-signing-failed-for-rsa-priv-auth-pubkey-error-in-libcrypto" tabindex="-1">Error: signing failed for RSA &quot;PRIV AUTH pubkey: error in libcrypto&quot; <a class="header-anchor" href="#error-signing-failed-for-rsa-priv-auth-pubkey-error-in-libcrypto" aria-label="Permalink to &quot;Error: signing failed for RSA &quot;PRIV AUTH pubkey: error in libcrypto&quot;&quot;">​</a></h5><p>Don&#39;t forget to youch your key, when authenticating 😉. It may be possible that you use unsupported algos, such as:</p><ul><li>rsa4096</li><li>ed25519</li><li>x25519 (failed on certificate creation)</li></ul><p>Known working algos are:</p><ul><li>rsa1024 (probably, pls. don&#39;t use)</li><li>rsa2048 (default)</li><li>rsa3072</li><li>eccp384 (sign-only, no de/encryption, prefer this for ssh)</li></ul><h4 id="agent-forwarding" tabindex="-1">Agent forwarding <a class="header-anchor" href="#agent-forwarding" aria-label="Permalink to &quot;Agent forwarding&quot;">​</a></h4><p>You can forward the YubiKey&#39;s authentication capabilities to the remote server, so that you can use this server as a jump host to another remote destination.<br> A classic example is developing on a remote machine and using SSH to push the changes to GitLab.</p><p>You must set your <code>pin-policy</code> to <code>once</code> (not <code>always</code>). You cannot change this setting after key creation (you must create new keys).</p><p>To enable agent forwarding you must load your SSH the key into your agent using:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">add </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;C:\\Program Files\\Yubico\\Yubico PIV Tool\\bin\\libykcs11.dll&quot;</span></span></code></pre></div><p>You can check if this was successfull using <code>ssh-add -L</code> and, if necessary, clear the key using <code>ssh-add -D</code>.</p><p>Your client must know to which remote hosts it should forward the agent. Use <code>ssh -A user@ip</code> to forward the agent.<br> You can optionally add <code>ForwardAgent yes</code> to your <code>~\\.ssh\\config</code>, e.g.:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host alias1 alias2</span></span>
<span class="line"><span>    HostName HostOrIp</span></span>
<span class="line"><span>    PKCS11Provider &quot;C:\\Program Files\\OpenSC Project\\OpenSC\\pkcs11\\opensc-pkcs11.dll&quot;</span></span>
<span class="line"><span>    User username</span></span>
<span class="line"><span>    ForwardAgent yes</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Don&#39;t forward the agent to all destinations. Only to destinations where needed.</p></div><p>Now the remote host also needs to accept your forwarded agent. Add <code>AllowAgentForwarding yes</code> to <code>/etc/ssh/sshd_config</code> on the remote host.<br> Reconnect and check if the agent was forwarded:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-rsa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AAAAB...</span></span></code></pre></div><p>Your agent was forwarded successfully. You can now connect to other destinations from there. 🍵</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>TODO<br> See also: <a href="https://github.com/pavel-odintsov/yubikey-ssh" target="_blank" rel="noreferrer">YubiKey SSH guide</a></p><h2 id="gpg" tabindex="-1">GPG <a class="header-anchor" href="#gpg" aria-label="Permalink to &quot;GPG&quot;">​</a></h2><p>Setup only.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt update</span></span>
<span class="line"><span>sudo apt install -y \\</span></span>
<span class="line"><span>  gnupg2 \\</span></span>
<span class="line"><span>  gnupg-agent \\</span></span>
<span class="line"><span>  scdaemon \\</span></span>
<span class="line"><span>  pcscd \\</span></span>
<span class="line"><span>  pcsc-tools \\</span></span>
<span class="line"><span>  yubikey-personalization</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>sudo systemctl enable --now pcscd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>~/.gnupg/gpg-agent.conf</span></span>
<span class="line"><span>enable-ssh-support</span></span>
<span class="line"><span>default-cache-ttl 600</span></span>
<span class="line"><span>max-cache-ttl 7200</span></span>
<span class="line"><span>pinentry-program /usr/bin/pinentry-gnome3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>gpgconf --kill gpg-agent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>in .bashrc /.zshrc</span></span>
<span class="line"><span>export SSH_AUTH_SOCK=$(gpgconf --list-dirs agent-ssh-socket)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>gpgconf --launch gpg-agent</span></span></code></pre></div><p>Certificate creation: TODO</p>`,46)])])}const g=e(t,[["render",o]]);export{h as __pageData,g as default};
